        }, 2000);
    };

    for (const filePath of [FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH]) {
        try {
            fs.watch(filePath, () => triggerSync());
            console.log(`[watch] Watching ${path.basename(filePath)}`);
